mapper.insert:
/** UsptExpertClMapngDao.insertExpertClMapng */
insert into uspt_expert_cl_mapng
	(
		  expert_id
		, expert_cl_id
		, creator_id
		, created_dt
	)
	values
	(
		  #{expertId}
		, #{expertClId}
		, #{creatorId}
		, #{createdDt}
	)

mapper.delete:
/** UsptExpertClMapngDao.deleteExpertClMapng */
delete from uspt_expert_cl_mapng
where expert_id 	= #{expertId}
  and expert_cl_id 	= #{expertClId}

mapper.select:
/** UsptExpertClMapngDao.selectExpertCount */ select count(1) as cnt from uspt_expert /**전문가**/ where 1=1
and wrc_nm like '%' || #{wrcNm} || '%'
and expert_nm like '%' || #{expertNm} || '%'

/** UsptExpertClMapngDao.selectExpertList */ select expert_id /**전문가ID**/ , expert_nm /**전문가명**/ , wrc_nm /**부서명**/ , ofcps_nm /**직위명**/ from uspt_expert /**전문가**/ where 1=1
and wrc_nm like '%' || #{wrcNm} || '%'
and expert_nm like '%' || #{expertNm} || '%'
offset #{beginRowNum} -1 limit #{itemsPerPage}

mapper.update:
/** UsptExpertClMapngDao.update */
	update uspt_expert_cl_mapng
		 set  expert_cl_id      = #{expertClId}
	where   expert_id 		= #{expertId}

mapper.delete:
/** UsptExpertClMapngDao.deleteExpert*/
delete from uspt_expert_cl_mapng
where expert_id = #{expertId}

mapper.select:
/** UsptExpertClMapngDao.selectCheckCnt */
select count(1)  as cnt
from uspt_expert_cl_mapng
where expert_id 	= #{expertId}
  and expert_cl_id 	= #{expertClId}
